sql:
SELECT year, growth_rate
FROM growth_rates
WHERE method = 'geometric';

SELECT SUM(population) AS total_population
FROM demographics
WHERE year = 2014;

SELECT MAX(growth_rate) AS max_growth_rate
FROM growth_rates
WHERE demographic_id = 1;

external_knowledge:
; The term 'highest growth rates' refers to the regions with the highest growth rate of population; 
; The term 'top three regions' means the regions with the first three ranks when ordered by growth rate in descending order; 
; The year '2023' is the specific time frame of interest for this query.

